# DK LBS.  Laurbjerg - Silkeborg
#
let ls = path("d3.dk.lbs");

with detail = 4, railway = :first :pax :removed {
    # point.dk.Laurbjerg  dk.FFH

    with link = "line.dk.LBS" {
        track(:lor,
                ls[:lau.ys - 0.1dl, :lau.ys] >> 1.5mo
            ..  ls[:lau.xs, :lau.xs + 0.1dl]
        );
        track(ls[:lau.xs, :lau.xs + 2.51km]);
        line_label(:right:se, ls[:lau.xs + 2.5km] >> 0.5mt, "LBS");
        track(ls[:lau.xs + 2.49km, :bos - 0.49sw]);
    }

    with link = "point.dk.Bøstrup", railway = :station {
        track(ls[:bos - 0.5sw, :bos + 0.5sw]);
        marker(:left :de.bf, ls[:bos] << 0.5mt);
        station(:right, ls[:bos] << 0.5mt << 1sh + (2dt, 2.2dt),
            "Bøstrup", "LBS: 5,7"
        );
    }

    with link = "line.dk.LBS" {
        track(ls[:bos + 0.49sw, :tho.ya - 0.49seg]);
    }

    with link = "point.dk.Thorsø", railway = :station {
        track(
                ls[:tho.ya, :tho + 300m - 1dl] << 1mo
            --  ls[:tho + 300m, :tho + 301m]
        );
        track(ls[:tho.ya - 0.5seg, :tho + 350m]);
        marker(:right :de.bf, ls[:tho] >> 0.5mt);
        station(:top, ls[:tho] >> 0.5mt >> 1sh >> 0.8dt,
            span(:bold, "Thorsø"),
            hbox(:center:top,
                vbox(:right:top, "LBS: ", "??: "),
                vbox(:sep:top,
                    hbox(:sep:base, "11,", anchor(), "8"),
                    hbox(:sep:base, "45,", anchor(), "8")
                )
            )
        );
    }

    with link = "line.dk.LBS" {
        track(ls[:tho + 349m, :tho + 1.71km]);
        line_label(:right:se, ls[:tho + 1.7km] >> 0.5mt, "LBS");
        track(ls[:tho + 1.69km, :gro - 0.49sw]);
    }

    with link = "point.dk.Grølsted", railway = :station {
        track(ls[:gro - 0.5sw, :gro + 0.5sw]);
        marker(:right :de.hp, ls[:gro] >> 0.5mt);
        station(:left, ls[:gro] >> 0.5mt >> 1sh + (-1.9dt, 1.1dt),
            "Grølsted", "LBS: 15,0"
        );
    }

    with link = "line.dk.LBS" {
        track(ls[:gro + 0.49sw, :far - 0.49sw]);
    }

    with link = "point.dk.Fårvang", railway = :station {
        track(ls[:far - 0.5sw, :far + 0.5sw]);
        marker(:right :de.bf, ls[:far] >> 0.5mt);
        station(:left, ls[:far] >> 0.5mt >> 1sh + (-1.8dt, 1.0dt),
            "Fårvang", "LBS: 17,0"
        );
    }

    with link = "line.dk.LBS" {
        track(ls[:far + 0.49sw, :hor - 0.49sw]);
    }

    with link = "point.dk.Horn", railway = :station {
        track(ls[:hor - 0.5sw, :hor + 0.5sw]);
        marker(:right :de.hp, ls[:hor] >> 0.5mt);
        station(:left :right_align,
            ls[:hor] >> 0.5mt >> 1sh + (-1.8dt, 1.1dt),
            "Horn", "LBS: 18,7 "
        );
    }

    with link = "line.dk.LBS" {
        track(ls[:hor + 0.49sw, :gje - 0.49sw]);
    }

    with link = "point.dk.Gjern", railway = :station {
        track(ls[:gje - 0.5sw, :gje + 0.5sw]);
        marker(:right :de.bf, ls[:gje] >> 0.5mt);
        station(:left :right_align,
            ls[:gje] >> 0.5mt >> 1sh + (-2dt, 0.5dt),
            "Gjern", "LBS: 22,0 "
        );
    }

    with link = "line.dk.LBS" {
        track(ls[:gje + 0.49sw, :gje + 1.91km]);
        line_label(:left:nw, ls[:gje + 1.9km] << 0.5mt, "LBS");
        track(ls[:gje + 1.89km, :smi - 0.49sw]);
    }

    with link = "point.dk.Sminge", railway = :station {
        track(ls[:smi - 0.5sw, :smi + 0.5sw]);
        marker(:right :de.hp, ls[:smi] >> 0.5mt);
        marker(:right :de.exbf, ls[:smi] >> 0.5mt);
        station(:top, ls[:smi] >> 0.5mt >> 1.4sh + (-0.8dt, -0.9dt),
            "Sminge", "LBS: 26,4"
        );
    }

    with link = "line.dk.LBS" {
        track(ls[:smi + 0.49sw, :res - 0.49sw]);
    }

    with link = "point.dk.Resenbro", railway = :station {
        track(ls[:res - 0.5sw, :res + 0.5sw]);
        marker(:right :de.bf, ls[:res] >> 0.5mt);
        station(:top, ls[:res] >> 0.5mt >> 1sh + (-2.0dt, -1.1dt),
            "Resenbro", "LBS: 30,5"
        );
    }

    with link = "line.dk.LBS" {
        track(ls[:res + 0.49sw, :res + 4.81km]);
        line_label(:right:s, ls[:res + 4.8km] >> 0.5mt, "LBS");
        track(ls[:res + 4.79km, :sil.xl - 2mo]);
        track(:lor,
                ls[:sil.xl - 2.1mo, :sil.xl - 2mo]
            ..  ls[:sil.yl, :sil.yl + 0.1dl] >> 1ms >> 1mt
        );
    }

    # point.dk.Silkeborg  dk.SBS
}

